import React from "react";

function Form({ data, setData }) {
  const handleChange = (e) => {
    setData({
      ...data,
      [e.target.name]: e.target.value
    });
  };

  return (
    <div style={{ width: "50%" }}>
      <h2>Form</h2>

      {/* Basic Info */}
      <input
        type="text"
        name="name"
        placeholder="Enter Name"
        value={data.name}
        onChange={handleChange}
      />
      <br /><br />

      <input
        type="email"
        name="email"
        placeholder="Enter Email"
        value={data.email}
        onChange={handleChange}
      />
      <br /><br />

      <input
        type="text"
        name="phone"
        placeholder="Enter Phone"
        value={data.phone}
        onChange={handleChange}
      />
      <br /><br />

      <textarea
        name="skills"
        placeholder="Enter Skills"
        value={data.skills}
        onChange={handleChange}
      />

      {/* Education */}
      <h3>Education</h3>

      {data.education.map((edu, index) => (
        <div key={index}>
          <input
            type="text"
            placeholder="College"
            value={edu.college}
            onChange={(e) => {
              const newEdu = [...data.education];
              newEdu[index].college = e.target.value;
              setData({ ...data, education: newEdu });
            }}
          />

          <input
            type="text"
            placeholder="Degree"
            value={edu.degree}
            onChange={(e) => {
              const newEdu = [...data.education];
              newEdu[index].degree = e.target.value;
              setData({ ...data, education: newEdu });
            }}
          />

          <input
            type="text"
            placeholder="Year"
            value={edu.year}
            onChange={(e) => {
              const newEdu = [...data.education];
              newEdu[index].year = e.target.value;
              setData({ ...data, education: newEdu });
            }}
          />

          <button onClick={() => {
            const newEdu = data.education.filter((_, i) => i !== index);
            setData({ ...data, education: newEdu });
          }}>
            Remove
          </button>

          <br /><br />
        </div>
      ))}

      <button onClick={() => {
        setData({
          ...data,
          education: [...data.education, { college: "", degree: "", year: "" }]
        });
      }}>
        Add Education
      </button>

      {/* Experience */}
      <h3>Experience</h3>

      {data.experience.map((exp, index) => (
        <div key={index}>
          <input
            type="text"
            placeholder="Company"
            value={exp.company}
            onChange={(e) => {
              const newExp = [...data.experience];
              newExp[index].company = e.target.value;
              setData({ ...data, experience: newExp });
            }}
          />

          <input
            type="text"
            placeholder="Role"
            value={exp.role}
            onChange={(e) => {
              const newExp = [...data.experience];
              newExp[index].role = e.target.value;
              setData({ ...data, experience: newExp });
            }}
          />

          <input
            type="text"
            placeholder="Year"
            value={exp.year}
            onChange={(e) => {
              const newExp = [...data.experience];
              newExp[index].year = e.target.value;
              setData({ ...data, experience: newExp });
            }}
          />

          <button onClick={() => {
            const newExp = data.experience.filter((_, i) => i !== index);
            setData({ ...data, experience: newExp });
          }}>
            Remove
          </button>

          <br /><br />
        </div>
      ))}

      <button onClick={() => {
        setData({
          ...data,
          experience: [...data.experience, { company: "", role: "", year: "" }]
        });
      }}>
        Add Experience
      </button>

    </div>
  );
}

export default Form;
